export * from "./collapsible";
export * as Collapsible from "./namespace";
export * from "./styles";

"use client";

import {
  Button,
  composeRenderProps,
  Disclosure,
  DisclosurePanel,
} from "react-aria-components";
import { CollapsibleStyles } from "./styles";

export interface CollapsibleRootProps
  extends React.ComponentProps<typeof Disclosure> {}

export function CollapsibleRoot(props: CollapsibleRootProps) {
  return <Disclosure data-slot="collapsible-root" {...props} />;
}

export interface CollapsibleTriggerProps
  extends Omit<React.ComponentProps<typeof Button>, "slot"> {}

export function CollapsibleTrigger(props: CollapsibleTriggerProps) {
  return <Button data-slot="collapsible-trigger" slot="trigger" {...props} />;
}

export interface CollapsibleContentProps
  extends React.ComponentProps<typeof DisclosurePanel> {}

export function CollapsibleContent({
  className,
  ...props
}: CollapsibleContentProps) {
  return (
    <DisclosurePanel
      className={composeRenderProps(className, (className) =>
        CollapsibleStyles.Content({ className })
      )}
      data-slot="collapsible-content"
      {...props}
    />
  );
}

import { cva } from "~/registry/lib/cva";

export const CollapsibleStyles = {
  Content: cva({
    base: [
      "overflow-hidden text-sm transition-[height,content_visibility] transition-discrete [interpolate-size:allow-keywords] aria-hidden:h-0",
    ],
  }),
};

export {
  CollapsibleContent as Content,
  CollapsibleRoot as Root,
  CollapsibleTrigger as Trigger,
} from "./collapsible";
